qry:select.qry:xquery:
					for $r in sql('		
					SELECT 
						PRY07_SOLICITUDES.oi_solicitud,
					  PRY07_SOLICITUDES.f_solicitud,
  					PRY07_SOLICITUDES.c_solicitud
					FROM 
						PRY07_SOLICITUDES,
						PRY08_CONTACTOS,
						PRY11_MODULOS,
						PRY11_APLICACIONES
					JOIN
						PRY07_SOLICITUDES.oi_modulo LEFT OUTER PRY11_MODULOS.oi_modulo,
						PRY11_MODULOS.oi_aplicacion LEFT OUTER PRY11_APLICACIONES.oi_aplicacion,
						PRY07_SOLICITUDES.oi_contacto LEFT OUTER PRY08_CONTACTOS.oi_contacto				
			    WHERE 1=1
          {%? (#PARAM:@f_hasta!='') {% AND PRY07_SOLICITUDES.f_solicitud <= {#PARAM:@f_hasta} %} {% %} %}
          {%? (#PARAM:@f_desde!='') {% AND PRY07_SOLICITUDES.f_solicitud >= {#PARAM:@f_desde} %} {% %} %}
          {%? (#PARAM:@f_hasta_v!='') {% AND PRY07_SOLICITUDES.f_estim_implem <= {#PARAM:@f_hasta_v} %} {% %} %}
          {%? (#PARAM:@f_desde_v!='') {% AND PRY07_SOLICITUDES.f_estim_implem >= {#PARAM:@f_desde_v} %} {% %} %}
          {%? (string(#PARAM:@c_solicitud)!='') {% AND CONTAIN(PRY07_SOLICITUDES.c_solicitud,{#PARAM:@c_solicitud}) %} {% %} %}
          {%? (string(#PARAM:@d_solicitud)!='') {% AND CONTAIN(PRY07_SOLICITUDES.d_solicitud,{#PARAM:@d_solicitud}) %} {% %} %}
					{%? (string(#PARAM:@oi_recurso)!='') {% AND PRY07_SOLICITUDES.oi_recurso = {#PARAM:@oi_recurso} %} {% %} %}
					{%? (string(#PARAM:@oi_aplicacion)!='') {% AND PRY11_MODULOS.oi_aplicacion = {#PARAM:@oi_aplicacion} %} {% %} %}
					{%? (string(#PARAM:@oi_modulo)!='') {% AND PRY07_SOLICITUDES.oi_modulo = {#PARAM:@oi_modulo} %} {% %} %}
					{%? (string(#PARAM:@oi_cliente)!='') {% AND PRY08_CONTACTOS.oi_cliente = {#PARAM:@oi_cliente} %} {% %} %}
					{%? (string(#PARAM:@oi_contacto)!='') {% AND PRY07_SOLICITUDES.oi_contacto = {#PARAM:@oi_contacto} %} {% %} %}
					{%? (string(#PARAM:@c_reclamo)!='') {% AND PRY07_SOLICITUDES.c_reclamo = {#PARAM:@c_reclamo} %} {% %} %}  
					{%? (string(#PARAM:@c_formulario)!='') {% AND PRY07_SOLICITUDES.c_formulario = {#PARAM:@c_formulario} %} {% %} %}
         	{%? (string(#PARAM:EST/C/@id)!='') {% AND PRY07_SOLICITUDES.c_estado in ({%=string(#PARAM:EST/C/@id) %}) %} {%  %} %}
         	{%? (string(#PARAM:CLASIF/C/@id)!='') {% AND PRY07_SOLICITUDES.oi_clasificacion in ({%=string(#PARAM:CLASIF/C/@id) %}) %} {%  %} %}
          ORDER BY
  					f_solicitud DESC,
  					c_solicitud DESC
				')/ROWS/ROW
